def ecdf(data):
    """
    Calculates the empirical cumulative distribution function (ECDF) of a dataset.

    Args:
        data (np.ndarray): A one-dimensional array of numerical data.

    Returns:
        function: A function that takes a value as input and returns the ECDF value at that point.
    """
    data = np.sort(data)
    n = len(data)

    def ecdf_function(x):
        if x < data[0]:
            return 0
        elif x > data[-1]:
            return 1
        else:
            indices = np.where(data >= x)[0]
            if len(indices) > 0:
                return (indices[0] + 1) / (n + 1)
            else:
                return 0
    return ecdf_function
