def longest_interval(data, threshold):
    """
    Finds the longest interval [low, high) such that ECDF(x) < threshold
    for any x in [low, high).
    """
    ecdf_values = ecdf(data)
    n = len(data)
    longest_low = None
    longest_high = None
    max_length = 0
    for i in range(n):
        for j in range(i, n):
            valid = True
            for k in range(i, j + 1):
                if ecdf(data)[k] >= threshold:
                    valid = False
                    break
            if valid:
                length = j - i + 1
                if length > max_length:
                    max_length = length
                    longest_low = data[i]
                    longest_high = data[j]
    return (longest_low, longest_high)

